-/* LinkButton text color override */
-.sl-link-button,
-.sl-link-button *,
-.sl-markdown-content .sl-link-button,
-.sl-markdown-content .sl-link-button *,
-.card .sl-link-button,
-.card .sl-link-button * {
+/* LinkButton text color override - only for primary buttons */
+.sl-link-button:not(.secondary):not(.minimal),
+.sl-link-button:not(.secondary):not(.minimal) *,
+.sl-markdown-content .sl-link-button:not(.secondary):not(.minimal),
+.sl-markdown-content .sl-link-button:not(.secondary):not(.minimal) *,
+.card .sl-link-button:not(.secondary):not(.minimal),
+.card .sl-link-button:not(.secondary):not(.minimal) * {
   color: var(--sl-color-text-invert) !important;
   text-decoration: none !important;
   --sl-color-black: var(--sl-color-text-invert) !important;
 }

+/* Secondary and minimal buttons preserve their own color rules */
+.sl-link-button.secondary,
+.sl-link-button.secondary *,
+.sl-link-button.minimal,
+.sl-link-button.minimal * {
+  text-decoration: none !important;
+}
